      /* <flatten type="Javascript"> */
function active$VoucherFilter$(sender) {
  sender.add_onResponseComplete(on$Filter$ResponseComplete);
  changeLookupReadonly(sender, 'ma_dvcs');
  var o = sender.getItem('maxLength');
  o.value = o.maxLength;
}
function close$VoucherFilter$(sender) {try {sender.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      var g = f.grid, dFrom = f.getItem('tu_ngay').value, dTo = f.getItem('den_ngay').value, q = f.getItemValue('chon_tt');
      g._alterTitle = [null, [['%d1', dFrom, true], ['%d2', dTo, true]]];
      g._queryFilterString = getQueryFilterString(f, 'tu_ngay, den_ngay, ma_dvcs, mau_bc');
      if (g._$k != null) g._$k = [];
      g._hiddenFields = [{Fields: 'Tien_nt', Value: (f.getItemValue('mau_bc') == '10')}];
      g._hiddenForms = [{Form: [0, 1, 2, 3, 4], Value: (q != '1')}, {Form: [5, 6], Value: (q == '1')}];
      remove$GridReport$Filter(g);
      break;
    default:
      break;
  }
}
function onChange$Item(o) {
  var f = o.parentForm, v = true;
  if (o.value != '') v = false;
  f.getItem('kieu_in').checked = v;
}
